export function getDemoDoc(documentId: string): DemoDoc | undefined {
  return DEMO_DOCS[documentId];
}

export function getCachedAdaptation(documentId: string, audienceId: string): (CachedAdaptation & { audienceName: string; formatName: string }) | undefined {
  const doc = DEMO_DOCS[documentId];
  if (!doc) return undefined;
  const adaptation = doc.adaptations[audienceId];
  if (!adaptation) return undefined;
  return {
    ...adaptation,
    audienceName: AUDIENCE_NAMES[audienceId] || audienceId,
    formatName: "Executive Summary"
  };
}

export function getAllDemoDocs(): { id: string; doc: DemoDoc }[] {
  return Object.entries(DEMO_DOCS).map(([id, doc]) => ({ id, doc }));
}

export function isDemoDoc(documentId: string): boolean {
  return documentId in DEMO_DOCS;
}

export function getDemoOrganizations(documentId: string): DemoOrg[] {
  return DEMO_DOCS[documentId]?.organizations ?? [];
}
